// Defines the possible positions for the modal on the screen.
export type Position = 'top' | 'left' | 'right' | 'bottom' | 'center';
// Defines the shape of the modal's corners.
export type Shape = 'square' | 'rounded';
// Defines the possible positions for the modal's close button, or if it should not be displayed.
export type CloseButtonPosition = 'left' | 'right' | 'none';
// Defines the standard set of sizes for the modal component.
export type Size = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
